      "path": "package.json",
      "content": "{
  "name": "project-management-api",
  "version": "1.0.0",
  "description": "A Node.js monolithic API for managing projects, tasks, members, and comments.",
  "main": "src/server.js",
  "scripts": {
    "start": "node src/server.js"
  },
  "dependencies": {
    "express": "^4.17.1"
  }
}"
    },
    {
      "path": "src/app.js",
      "content": "const express = require('express');
const projectsRouter = require('./modules/projects/routes');
const membersRouter = require('./modules/members/routes');
const tasksRouter = require('./modules/tasks/routes');
const commentsRouter = require('./modules/comments/routes');

const app = express();
app.use(express.json());

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.use('/projects', projectsRouter);
app.use('/projects/:projectId/members', membersRouter);
app.use('/projects/:projectId/tasks', tasksRouter);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRouter);

module.exports = app;"
    },
    {
      "path": "src/server.js",
      "content": "const app = require('./app');
const PORT = process.env.PORT || 3000;

app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});"
    },
    {
      "path": "src/modules/projects/routes.js",
      "content": "const express = require('express');
const { createProject, getProjects, getProjectById } = require('./service');
const { validateProjectInput } = require('../../lib/errors');

const router = express.Router();

router.post('/', validateProjectInput, createProject);
router.get('/', getProjects);
router.get('/:projectId', getProjectById);

module.exports = router;"
    },
    {
      "path": "src/modules/projects/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const projects = [];

const createProject = (req, res) => {
  const { name } = req.body;
  const projectId = randomUUID();
  projects.push({ id: projectId, name });
  res.status(201).json({ project: { id: projectId, name } });
};

const getProjects = (req, res) => {
  res.json({ projects });
};

const getProjectById = (req, res) => {
  const { projectId } = req.params;
  const project = projects.find(p => p.id === projectId);
  if (!project) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Project not found' } });
  }
  res.json({ project });
};

module.exports = { createProject, getProjects, getProjectById };"
    },
    {
      "path": "src/modules/members/routes.js",
      "content": "const express = require('express');
const { addMember, getMembers } = require('./service');
const { validateMemberInput } = require('../../lib/errors');

const router = express.Router();

router.post('/', validateMemberInput, addMember);
router.get('/', getMembers);

module.exports = router;"
    },
    {
      "path": "src/modules/members/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const members = [];

const addMember = (req, res) => {
  const { userId, role } = req.body;
  const memberId = randomUUID();
  members.push({ id: memberId, userId, role });
  res.status(201).json({ member: { id: memberId, userId, role } });
};

const getMembers = (req, res) => {
  res.json({ members });
};

module.exports = { addMember, getMembers };"
    },
    {
      "path": "src/modules/tasks/routes.js",
      "content": "const express = require('express');
const { createTask, getTasks, getTasksByStatus } = require('./service');
const { validateTaskInput } = require('../../lib/errors');

const router = express.Router();

router.post('/', validateTaskInput, createTask);
router.get('/', getTasks);
router.get('?status=done', getTasksByStatus);

module.exports = router;"
    },
    {
      "path": "src/modules/tasks/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const tasks = [];

const createTask = (req, res) => {
  const { title } = req.body;
  const taskId = randomUUID();
  tasks.push({ id: taskId, title, status: 'pending' });
  res.status(201).json({ task: { id: taskId, title, status: 'pending' } });
};

const getTasks = (req, res) => {
  res.json({ tasks });
};

const getTasksByStatus = (req, res) => {
  const { status } = req.query;
  const filteredTasks = tasks.filter(task => task.status === status);
  res.json({ tasks: filteredTasks });
};

module.exports = { createTask, getTasks, getTasksByStatus };"
    },
    {
      "path": "src/modules/comments/routes.js",
      "content": "const express = require('express');
const { addComment, getComments } = require('./service');
const { validateCommentInput } = require('../../lib/errors');

const router = express.Router();

router.post('/', validateCommentInput, addComment);
router.get('/', getComments);

module.exports = router;"
    },
    {
      "path": "src/modules/comments/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const comments = [];

const addComment = (req, res) => {
  const { message } = req.body;
  const commentId = randomUUID();
  comments.push({ id: commentId, message });
  res.status(201).json({ comment: { id: commentId, message } });
};

const getComments = (req, res) => {
  res.json({ comments });
};

module.exports = { addComment, getComments };"
    },
    {
      "path": "src/lib/errors.js",
      "content": "const validateProjectInput = (req, res, next) => {
  const { name } = req.body;
  if (!name || typeof name !== 'string') {
    return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'Invalid project name' } });
  }
  next();
};

const validateMemberInput = (req, res, next) => {
  const { userId, role } = req.body;
  if (!userId || typeof userId !== 'string' || !role || typeof role !== 'string') {
    return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'Invalid member input' } });
  }
  next();
};

const validateTaskInput = (req, res, next) => {
  const { title } = req.body;
  if (!title || typeof title !== 'string') {
    return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'Invalid task title' } });
  }
  next();
};

const validateCommentInput = (req, res, next) => {
  const { message } = req.body;
  if (!message || typeof message !== 'string') {
    return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'Invalid comment message' } });
  }
  next();
};

module.exports = { validateProjectInput, validateMemberInput, validateTaskInput, validateCommentInput };"
    }
  ]
}
